CREATE VIEW `ads_short_video_series_unlock_view` (`id` COMMENT "剧集解锁表主键id", `user_id` COMMENT "用户id", `series_id` COMMENT "剧id", `epis_id` COMMENT "具体集数id", `create_time` COMMENT "创建时间", `epis_num` COMMENT "第几集", `series_name` COMMENT "剧名称", `bill_id` COMMENT "订单流水id", `region_id` COMMENT "归属区域 id，1：香港，2：北美；", `expire_time` COMMENT "过期时间,广告解锁的会有具体的过期时间,付费解锁的全都是9999年", `purchase_type` COMMENT "购买（解锁）类型：0-普通购买；1-超前点播购买,2:打包售卖,3:跨集解锁，4：批量购买，5：免费解锁    select * from dim.dim_dic where dic_column ='purchase_type'  ", `show_type` COMMENT "解锁详情展示类型：0或null——按集展示，1按剧展示", `start_epis_num` COMMENT "跨集解锁开始集数，只有跨集解锁才有值", `sr_updatetime` COMMENT "ods同步时间", `sr_createtime` COMMENT "starrocks数据注入时间")
COMMENT "海外短剧-剧集解锁表" AS (SELECT `ods`.`ods_tidb_short_video_series_unlock`.`id`, `ods`.`ods_tidb_short_video_series_unlock`.`accountid` AS `account_id`, `ods`.`ods_tidb_short_video_series_unlock`.`seriesid` AS `series_id`, `ods`.`ods_tidb_short_video_series_unlock`.`episid` AS `epis_id`, `ods`.`ods_tidb_short_video_series_unlock`.`createtime` AS `create_time`, `ods`.`ods_tidb_short_video_series_unlock`.`episnum` AS `epis_num`, `ods`.`ods_tidb_short_video_series_unlock`.`seriesname` AS `series_name`, `ods`.`ods_tidb_short_video_series_unlock`.`billid` AS `bill_id`, `ods`.`ods_tidb_short_video_series_unlock`.`regionid` AS `region_id`, `ods`.`ods_tidb_short_video_series_unlock`.`ExpireTime`, `ods`.`ods_tidb_short_video_series_unlock`.`PurchaseType`, `ods`.`ods_tidb_short_video_series_unlock`.`showtype`, `ods`.`ods_tidb_short_video_series_unlock`.`StartEpisNum`, `ods`.`ods_tidb_short_video_series_unlock`.`sr_updatetime`, `ods`.`ods_tidb_short_video_series_unlock`.`sr_createtime`
FROM `ods`.`ods_tidb_short_video_series_unlock`);